// Simulate sensor readings
const mq135 = (Math.random() * 400 + 100).toFixed(2);
const mq5 = (Math.random() * 300 + 50).toFixed(2);

// Prepare for ML API
msg.ml_payload = {
    MQ135: parseFloat(mq135),
    MQ5: parseFloat(mq5)
};

// Store in InfluxDB
msg.payload = {
    MQ135: parseFloat(mq135),
    MQ5: parseFloat(mq5)
};

msg.sensor_values = `MQ135=${mq135}, MQ5=${mq5}`;
node.status({fill:"green",shape:"dot",text:msg.sensor_values});

return msg;

// Prepare payload for FastAPI
msg.payload = msg.ml_payload;
msg.headers = {
    'Content-Type': 'application/json'
};

return msg;

// Extract predictions from HYBRID API response (LSTM + SVM)
const predictions = msg.payload.predictions || {};
const co = predictions.co || 0;
const ethanol = predictions.ethanol || 0;
const temperature = predictions.temperature || 0;  // LSTM temperature prediction

// NEW: SVM classification result (additional to LSTM)
const svmClassification = msg.payload.svm_classification || {};
const svmClass = svmClassification.class || 'NORMAL';
const svmConfidence = svmClassification.confidence || 0;

// Get overall alert level from API (API combines LSTM + SVM)
const apiAlertLevel = msg.payload.alert_level || 'NORMAL';

const processingTime = msg.payload.processing_time_ms || 0;
const sensorInput = msg.payload.sensor_input || {};

// Determine alert message and emoji based on API alert level
let alertLevel = apiAlertLevel.toLowerCase();
let alertMsg = "";
let alertEmoji = "";
let shouldAlert = false;

if (alertLevel === "danger") {
    if (co > 0.7) {
        alertMsg = `🚨 CRITICAL: High CO detected (${co.toFixed(4)})`;
    } else {
        alertMsg = `🚨 DANGER: ${svmClass} condition detected`;
    }
    alertEmoji = "🚨";
    shouldAlert = true;
} else if (alertLevel === "warning") {
    if (co > 0.5) {
        alertMsg = `⚠️ WARNING: Elevated CO (${co.toFixed(4)})`;
    } else if (ethanol > 0.6) {
        alertMsg = `⚠️ WARNING: High Ethanol (${ethanol.toFixed(4)})`;
    } else {
        alertMsg = `⚠️ WARNING: ${svmClass} condition from SVM`;
    }
    alertEmoji = "⚠️";
    shouldAlert = true;
} else {
    alertMsg = "✅ All parameters normal";
    alertEmoji = "✅";
    shouldAlert = false;
}

// Prepare output message
msg.predictions = {
    co: co,
    ethanol: ethanol,
    temperature: temperature,
    svm_class: svmClass,
    svm_confidence: svmConfidence,
    alert_level: alertLevel,
    alert_message: alertMsg,
    processing_time_ms: processingTime,
    timestamp: msg.payload.timestamp,
    sensor_input: sensorInput
};

// Set node status
let statusColor = "green";
if (alertLevel === "warning") statusColor = "yellow";
if (alertLevel === "danger") statusColor = "red";

node.status({
    fill: statusColor,
    shape: "dot",
    text: alertMsg
});

// Prepare alert message for Telegram
msg.alert = {
    level: alertLevel,
    message: alertMsg,
    emoji: alertEmoji,
    values: { 
        co: co.toFixed(4), 
        ethanol: ethanol.toFixed(4),
        temperature: temperature.toFixed(4)
    },
    svm: {
        class: svmClass,
        confidence: svmConfidence ? (svmConfidence * 100).toFixed(1) + '%' : 'N/A'
    },
    sensor: {
        mq135: sensorInput.MQ135 ? sensorInput.MQ135.toFixed(2) : 'N/A',
        mq5: sensorInput.MQ5 ? sensorInput.MQ5.toFixed(2) : 'N/A'
    },
    timestamp: new Date().toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' })
};

// Only send to Telegram if alert is warning or danger
if (shouldAlert) {
    return [msg, msg]; // Output to both InfluxDB and Telegram
}

return [msg, null]; // Only InfluxDB, no Telegram

// Prepare predictions for InfluxDB
const pred = msg.predictions;

// IMPORTANT: Use alert_level (normalized LSTM + SVM) NOT raw svm_class
// alert_level is determined by ML API with proper normalization
const alertStatus = pred.alert_level === "danger" ? 2 : (pred.alert_level === "warning" ? 1 : 0);

// For backward compatibility: svm_status = alert_status (use same value)
const svmStatus = alertStatus;

// InfluxDB node expects simple object in msg.payload
msg.payload = {
    pred_co: pred.co,
    pred_ethanol: pred.ethanol,
    pred_temperature: pred.temperature,
    svm_status: svmStatus,
    alert_status: alertStatus,
    processing_time_ms: pred.processing_time_ms
};

return msg;

// Format beautiful Telegram alert message
const alert = msg.alert;

// Build formatted message with emojis and formatting
let message = `${alert.emoji} *GAS MONITORING ALERT* ${alert.emoji}\n\n`;
message += `*Alert Level:* ${alert.level.toUpperCase()}\n`;
message += `*Message:* ${alert.message}\n\n`;

// LSTM Predictions section
message += `📊 *LSTM Predictions:*\n`;
message += `  • CO: \`${alert.values.co}\`\n`;
message += `  • Ethanol: \`${alert.values.ethanol}\`\n\n`;

// SVM Classification section (NEW)
if (alert.svm) {
    message += `🤖 *SVM Classification:*\n`;
    message += `  • Status: \`${alert.svm.class}\`\n`;
    message += `  • Confidence: \`${alert.svm.confidence}\`\n\n`;
}

// Sensor readings section
message += `🔬 *Sensor Readings:*\n`;
message += `  • MQ135: \`${alert.sensor.mq135}\` ppm\n`;
message += `  • MQ5: \`${alert.sensor.mq5}\` ppm\n\n`;

// Threshold info
message += `⚙️ *Thresholds:*\n`;
if (alert.level === "danger") {
    message += `  • CO > 0.7 (CRITICAL)\n`;
} else {
    message += `  • Ethanol > 0.6 or Temp > 0.8\n`;
}

// Timestamp
message += `\n🕐 *Time:* ${alert.timestamp}`;

// CRITICAL: telegram sender node needs both type and content
// REPLACE 123456789 with your actual Chat ID from @getidsbot
msg.payload = {
    type: "message",
    content: message,
    chatId: 8561028127  // CHANGE THIS to your Chat ID (number, no quotes)
};

// Also keep original alert data
msg.alert_data = alert;

node.status({
    fill: alert.level === "danger" ? "red" : "yellow",
    shape: "dot",
    text: `Sending ${alert.level} alert`
});

return msg;

// Create a test alert message
msg.alert = {
    level: "warning",
    message: "Test Alert - High CO Detected",
    emoji: "🧪",
    values: { 
        co: "0.8500", 
        ethanol: "0.4500", 
        temperature: "0.6200"
    },
    sensor: {
        mq135: "234.50",
        mq5: "123.40"
    },
    timestamp: new Date().toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' })
};

// IMPORTANT: Ensure chatId is set for telegram sender node
// The bot config should have this in Users tab, but we can also set it here
// msg.payload.chatId = "YOUR_CHAT_ID";  // Only if needed

return msg;
